: #000864; }\n\n/* Blog base CSS (extracted from styles.css) */\n.blog-hero {\n    background: linear-gradient(135deg, #0f1419 0%, #000432 40%, #000864 100%);\n    padding: 160px 24px 60px;\n    position: relative;\n    overflow: hidden;\n}\n.blog-hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-hero-inner {\n    max-width: 800px;\n    margin: 0 auto;\n    position: relative;\n    z-index: 1;\n}\n.blog-back-link {\n    display: inline-flex;\n    align-items: center;\n    gap: 6px;\n    color: rgba(255,255,255,0.85);\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    font-weight: 500;\n    text-decoration: none;\n    transition: color 0.3s ease;\n}\n.blog-back-link:hover {\n    color: #00AFF0;\n}\n.blog-back-link svg {\n    width: 16px;\n    height: 16px;\n    stroke: currentColor;\n}\n.blog-category-badge {\n    display: inline-block;\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: 11px;\n    font-weight: 500;\n    letter-spacing: 0.1em;\n    text-transform: uppercase;\n    color: #fff;\n    padding: 5px 12px;\n    border-radius: 4px;\n}\n.blog-hero h1 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: clamp(28px, 4.5vw, 42px);\n    font-weight: 700;\n    color: #fff;\n    line-height: 1.2;\n    margin-bottom: 20px;\n}\n.blog-meta {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    color: rgba(255,255,255,0.85);\n    display: flex;\n    align-items: center;\n    gap: 12px;\n}\n.blog-meta-dot {\n    width: 4px;\n    height: 4px;\n    border-radius: 50%;\n    background: rgba(255,255,255,0.3);\n}\n.blog-body {\n    max-width: 760px;\n    margin: 0 auto;\n    padding: 0 24px;\n}\n.blog-body h2 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 28px;\n    font-weight: 600;\n    color: #000864;\n    margin-top: 56px;\n    margin-bottom: 20px;\n    line-height: 1.3;\n}\n.blog-body h3 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 22px;\n    font-weight: 600;\n    color: #000864;\n    margin-top: 40px;\n    margin-bottom: 16px;\n    line-height: 1.35;\n}\n.blog-body p {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    line-height: 1.8;\n    color: #333333;\n    margin-bottom: 24px;\n}\n.blog-body ul, .blog-body ol {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    line-height: 1.8;\n    color: #333333;\n    margin-bottom: 24px;\n    padding-left: 24px;\n}\n.blog-body li {\n    margin-bottom: 8px;\n}\n.blog-body strong {\n    color: #000864;\n    font-weight: 600;\n}\n.blog-pullquote {\n    border-left: 4px solid #00AFF0;\n    padding: 8px 0 8px 24px;\n    margin: 40px 0;\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 20px;\n    font-style: italic;\n    color: #000864;\n    line-height: 1.6;\n}\n.blog-data-card {\n    background: linear-gradient(135deg, #000432 0%, #000864 100%);\n    border-radius: 12px;\n    padding: 40px;\n    margin: 40px 0;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n.blog-data-card::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-data-card-content {\n    position: relative;\n    z-index: 1;\n}\n.blog-data-number {\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: clamp(32px, 5vw, 48px);\n 