lumns: 1fr;\n        gap: 16px;\n    }\n    .blog-related-card {\n        padding: 24px 20px;\n    }\n    .blog-cta {\n        padding: 60px 20px;\n    }\n.blog-hero-inner {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 24px;\n    position: relative;\n    z-index: 2;\n    animation: slide-up 0.8s ease-out;\n}\n.blog-data-number--success {\n    color: var(--event-color, #22C55E);\n}\n.blog-data-label--spaced {\n    margin-top: 12px;\n}\n.dw-section {\n    padding: 100px 80px;\n}\n.dw-section--white {\n    background: #ffffff;\n}\n.dw-section--gray {\n    background: #F5F7FA;\n}\n.dw-section--dark {\n    background: linear-gradient(135deg, #000864 0%, #1e3a5f 100%);\n    color: #ffffff;\n}\n.dw-section--blue {\n    background: linear-gradient(135deg, #00AFF0 0%, #0ea5e9 50%, #0284c7 100%);\n    color: #ffffff;\n    position: relative;\n}\n.dw-section--blue::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: radial-gradient(ellipse at 20% 30%, rgba(255,255,255,0.15) 0%, transparent 50%);\n    pointer-events: none;\n}\n    .dw-section {\n        padding: 60px 40px;\n    }\n    .dw-section {\n        padding: 48px 24px;\n    }\n\n.blog-category-badge { background: #02D28C; }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="blog-hero" style="position: relative; overflow: hidden;">\n        <div class="dw-d-bg dw-d-bg--corner-br" style="opacity: 0.06;"></div>\n        <div class="blog-hero-inner" style="position: relative; z-index: 2;">\n            <a href="/blog/" class="blog-back-link">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n                Back to Insights\n            </a>\n            <div class="blog-category-badge">Cost Management</div>\n            <h1>Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces</h1>\n            <div class="blog-meta">\n                <span>6 min read</span>\n                <span class="blog-meta-dot"></span>\n                <span>February 2026</span>\n            </div>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Body"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Body: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Body: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><article class="blog-body">\n\n        <!-- Opening -->\n        <p class="fade-in">\n            Your sales team sells in pieces. Your production floor measures in kilograms. Your warehouse counts in boxes. Your purchasing team orders in rolls or sheets. Every department uses different units of measure for the same product — and somehow your ERP is supposed to keep everyone on the same page.\n        </p>\n\n        <p class="fade-in">\n            For many manufacturers, the ERP forces a choice: pick one primary unit, and convert everything else manually. This creates friction, errors, and wasted time at every handoff point. Sales enters an order for 500 pieces. Warehouse needs to know that\'s 125 kg. Production needs 3 rolls of raw material. Purchasing needs 2 pallets. Every conversion is manual — and every manual conversion is an error waiting to happen.\n        </p>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Section: The Single-Unit Problem -->\n        <h2 class="fade-in">The Single-Unit Problem</h2>\n\n        <p class="fade-in">\n            Many ERP systems — including certain major brands operating in Thailand — support only one primary unit of measure per item. You define a product as "kilograms" or "pieces" but not both simultaneously. The system picks one as the "master" unit, and everything else is treated as a conversion that must be calculated on the fly.\n        </p>\n\n        <p class="fade-in">\n            This seems like a reasonable technical decision until you live with the consequences. Sales enters an order for 500 pieces. Warehouse needs to know that\'s 125 kg. The system doesn\'t show both. The warehouse clerk has to remember — or look up — that this particular item weighs 0.25 kg per piece. If they get it wrong, they ship 120 kg when they should have shipped 125 kg. The customer receives 480 pieces instead of 500.\n        </p>\n\n        <p class="fade-in">\n            Production faces the same problem. The production order says to manufacture 1,000 units. The floor supervisor needs to know how many kilograms of raw material to requisition. The BOM (Bill of Materials) might show it in kg, but the production order shows units. Every handoff requires a mental conversion — or a separate lookup table — to connect what the system says to what the operation needs.\n        </p>\n\n        <p class="fade-in">\n            Purchasing encounters the inverse issue. Suppliers sell raw materials by the kilogram, roll, or sheet. Production consumes materials by the piece or meter. Inventory is tracked in yet another unit. When the purchasing team places an order, they need to translate production consumption rates (in pieces) into supplier order quantities (in kg or rolls). This translation happens outside the ERP, in spreadsheets or through manual calculation, because the system only understands one unit at a time.\n        </p>\n\n        <div class="blog-pullquote fade-in">\n            When your salesperson promises 500 pieces and your warehouse ships 120 kg, someone made a conversion error. Dual units eliminate the conversion entirely.\n        </div>\n\n        <!-- Section: What Dual Units Solve -->\n        <h2 class="fade-in">What Dual Units Solve</h2>\n\n        <p class="fade-in">\n            <a href="/products/erp/">DigiWin\'s manufacturing ERP</a> displays both units simultaneously. On one screen, you see: <strong>500 pieces = 125 kg</strong>. No mental math, no conversion tables, no "let me check." The system understands that this product is measured in two ways, and it shows both wherever they matter.\n        </p>\n\n        <p class="fade-in">\n            Inventory shows current stock in both units. If you have 240 kg in the warehouse, the screen also shows you have 960 pieces (assuming 0.25 kg per piece). Sales orders display the customer quantity in pieces and the warehouse fulfillment quantity in kg. Production orders show required output in pieces and material consumption in kg. Purchase orders display supplier units (kg, rolls, sheets) alongside the production units (pieces, meters) they translate into.\n        </p>\n\n        <p class="fade-in">\n            This isn\'t just convenience — it\'s accuracy. Every time a human has to convert units manually, there\'s a chance of error. Use the wrong conversion factor. Transpose digits. Forget to account for packaging waste. Round incorrectly. These errors propagate through the system until they surface as shipping discrepancies, production shortages, or inventory write-offs.\n        </p>\n\n        <div class="blog-data-card fade-in">\n            <div class="blog-data-card-content">\n                <div class="blog-data-number">2 Units, 1 Screen</div>\n                <div class="blog-data-label">See inventory, orders, and production in both measurement units simultaneously</div>\n            </div>\n        </div>\n\n        <p class="fade-in">\n            Dual units also matter for compliance and reporting. BOI-certified manufacturers often need to report material consumption in the units specified by import declarations — which may differ from the units used in production. If you import steel by the ton but produce parts by the kilogram (and sell them by the piece), your BOI report needs to reconcile all three. A dual-unit system makes this reconciliation automatic rather than manual.\n        </p>\n\n        <!-- Section: Where It Matters Most -->\n        <h2 class="fade-in">Where It Matters Most</h2>\n\n        <p class="fade-in">\n            Dual units are particularly critical in industries where the sales unit and the production unit naturally diverge, such as <a href="/industries/metal-plastics/">metal fabrication and plastics manufacturing</a>. Consider the following scenarios where single-unit ERPs create operational friction:\n        </p>\n\n        <ul class="fade-in">\n            <li><strong>Plastics:</strong> Resin is purchased and tracked by kilogram. Injection-molded parts are counted and sold by the piece. Production needs to know how many kg of resin are required to produce 10,000 pieces. Inventory needs to show both the kg remaining and how many pieces that translates into.</li>\n            <li><strong>Metal fabrication:</strong> Steel is bought by the ton. Sheets are cut and processed into parts counted by the unit. When a customer orders 5,000 brackets, purchasing needs to know how many tons of steel to order.</li>\n            <li><strong>Food manufacturing:</strong> Ingredients are purchased and measured by kilogram or liter. Finished goods are packaged and sold by the case or unit. The recipe (BOM) uses kg; the sales order uses cases.</li>\n            <li><strong>Chemicals:</strong> Raw materials are procured by the liter or barrel. Production consumes them by kilogram (weight-based). Finished products are sold by volume or by weight depending on the customer.</li>\n        </ul>\n\n        <p class="fade-in">\n            In every case, the organization is forced to choose one unit as "primary" and treat the other as secondary. This choice reverberates through every transaction. Warehouse staff calculate conversions. Sales staff check reference tables. Production planners maintain spreadsheets to translate between sales forecasts (in pieces) and material requirements (in kg).\n        </p>\n\n        <p class="fade-in">\n            The cost isn\'t just the time spent converting. It\'s the errors that result. A shipping mistake caused by a unit conversion error doesn\'t just delay a delivery — it damages customer trust, consumes internal labor to fix, and potentially triggers penalty clauses in supply agreements. Over hundreds of transactions per month, the cumulative impact becomes significant.\n        </p>\n\n        <div class="blog-highlight fade-in">\n            <p><strong>BOI reporting note:</strong> Bonded materials are often tracked in import units (tons, barrels, cases) while production consumption is measured in different units (kg, liters, pieces). Dual-unit display ensures BOI reconciliation reports show consumption in both the import unit and the production unit without requiring manual conversion.</p>\n        </div>\n\n        <hr class="blog-divider fade-in">\n\n        <!-- Closing -->\n        <h2 class="fade-in">A Small Feature with Large Impact</h2>\n\n        <p class="fade-in">\n            It seems like a small thing — two units on one screen. But across thousands of transactions per month, across every department, the cumulative impact of eliminating unit-of-measure conversion errors is significant.\n        </p>\n\n        <p class="fade-in">\n            Fewer shipping mistakes. Faster order processing. More accurate inventory. Cleaner BOI reports. Less time wasted looking up conversion factors. Fewer spreadsheets maintained outside the system to bridge the gap between what sales says and what production needs.\n        </p>\n\n        <p class="fade-in">\n            If your current ERP forces you to choose between kilograms and pieces, you\'ve already felt this friction. Your team has developed workarounds — reference tables, conversion spreadsheets, mental math routines. These workarounds function until they don\'t. And when they fail, the cost is immediate and measurable.\n        </p>\n\n        <p class="fade-in">\n            Dual-unit display isn\'t a luxury feature. It\'s the difference between an ERP that reflects how your business actually operates and one that forces your business to conform to its limitations.\n        </p>\n\n    </article>\n\n    <!-- FAQ Section -->\n    <section class="dw-section" style="padding: 60px 0; background: #f8fafc;">\n      <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px;">Frequently Asked Questions</h2>\n        <div style="display: flex; flex-direction: column; gap: 12px;">\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What are dual units of measure in ERP?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Dual units of measure is an ERP capability that tracks inventory and transactions in two units of measure simultaneously — for example, both kilograms and pieces on the same screen. Instead of forcing you to pick one primary unit and manually convert everything else, the system displays both units wherever they matter: inventory screens, sales orders, production orders, and purchase orders. This eliminates manual conversion errors and ensures every department sees quantities in the unit that is natural to their operation.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Why does my ERP need dual-unit support?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Different departments naturally think in different units: sales teams sell in pieces, production floors measure in kilograms, warehouses count in boxes, and purchasing orders in rolls or sheets. When your ERP only supports one primary unit, every handoff between departments requires a manual conversion — and every manual conversion is an error waiting to happen. Dual-unit support eliminates this friction, preventing shipping mistakes, production shortages, and inventory write-offs that result from conversion errors across thousands of transactions per month.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Which industries need dual-unit tracking?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Dual-unit tracking is particularly critical in industries where sales units and production units naturally diverge. Key industries include plastics manufacturing (resin purchased in kg, injection-molded parts sold by the piece), metal fabrication (steel bought by the ton, finished parts counted by the unit), food manufacturing (ingredients measured in kg or liters, finished goods sold by the case), and chemical processing (raw materials procured by the liter or barrel, production consumes by weight). BOI-certified manufacturers also benefit because bonded materials are often tracked in import units that differ from production consumption units.</p>\n            </div>\n          </details>\n        </div>\n      </div>\n    </section>\n\n    <!-- Related Articles --><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Related"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Related: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dual Units: Why Your ERP Should Show Both Kilograms AND Pieces: Related: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="blog-related" style="position: relative; overflow: hidden;">\n        <div class="dw-wave-fade" style="opacity: 0.08;"></div>\n        <div class="blog-related-inner" style="position: relative; z-index: 2;">\n            <h2 class="fade-in">Related Articles</h2>\n            <div class="blog-related-grid">\n                <a href="/blog/co-product-cost-accounting/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">Cost Management</div>\n                    <h3>Co-Product Cost Accounting: Allocating Costs When One Process Makes Many Products</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n                <a href="/blog/feature-codes/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">Production Planning</div>\n                    <h3>Feature Codes: How to Handle "Same Product, Different Specs" Without Drowning in SKUs</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n                <a href="/blog/boi-compliance-jin-hai/" class="blog-related-card fade-in">\n                    <div class="blog-related-card-category">BOI &amp; Compliance</div>\n                    <h3>How One Factory Saved 10M THB/Year in BOI Supplementary Taxes</h3>\n                    <span class="blog-related-card-link">\n                        Read article\n                        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>\n                    </span>\n                </a>\n            </div>\n        </div>\n    </section>\n\n    <!-- CTA Section -->\n    <section class="blog-cta">\n        <div class="blog-cta-inner">\n            <h2 class="fade-in">Tired of Unit Conversion Headaches?</h2>\n            <p class="fade-in">See how dual-unit display eliminates errors across your entire operation.</p>\n            <a href="/demo/" class="blog-cta-btn fade-in">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>\n                Let\'s Talk\n            </a>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
