n    font-size: clamp(24px, 4vw, 36px);\n    font-weight: 700;\n    color: #fff;\n    margin-bottom: 16px;\n    line-height: 1.25;\n}\n.blog-cta p {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 18px;\n    color: rgba(255,255,255,0.85);\n    line-height: 1.7;\n    margin-bottom: 32px;\n}\n.blog-cta-btn {\n    display: inline-flex;\n    align-items: center;\n    gap: 10px;\n    background: #00AFF0;\n    color: #fff;\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 16px;\n    font-weight: 600;\n    padding: 16px 36px;\n    border-radius: 8px;\n    text-decoration: none;\n    transition: all 0.3s ease;\n}\n.blog-cta-btn:hover {\n    background: #2b7bc4;\n    transform: translateY(-2px);\n    box-shadow: 0 8px 24px rgba(0, 175, 240, 0.3);\n}\n.blog-cta-btn svg {\n    width: 18px;\n    height: 18px;\n    stroke: currentColor;\n}\n.fade-in {\n    opacity: 0;\n    transform: translateY(16px);\n    transition: opacity 0.2s ease, transform 0.2s ease;\n}\n.fade-in.visible {\n    opacity: 1;\n    transform: translateY(0);\n}\n.fade-in.no-delay {\n    opacity: 1;\n    transform: none;\n    transition: none;\n}\n    .fade-in {\n        opacity: 1;\n        transform: none;\n        transition: none;\n    }\n    .blog-hero {\n        padding: 140px 20px 48px;\n    }\n    .blog-hero h1 {\n        font-size: 26px;\n    }\n    .blog-back-link {\n        min-height: 44px;\n        padding: 8px 0;\n    }\n    .blog-body {\n        padding: 0 20px;\n    }\n    .blog-body h2 {\n        font-size: 24px;\n        margin-top: 44px;\n    }\n    .blog-body p,\n    .blog-body ul,\n    .blog-body ol {\n        font-size: 17px;\n    }\n    .blog-pullquote {\n        font-size: 18px;\n        padding-left: 20px;\n        margin: 32px 0;\n    }\n    .blog-data-card {\n        padding: 28px 20px;\n    }\n    .blog-data-number {\n        font-size: 28px;\n    }\n    .blog-data-inline {\n        flex-direction: column;\n        gap: 8px;\n    }\n    .blog-related-grid {\n 